import{_ as e,o,c as r,ag as a}from"./chunks/framework.BZohXCq9.js";const b=JSON.parse('{"title":"Bot Management","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/bot.md","filePath":"getting-started/bot.md","lastUpdated":1772873936000}'),i={name:"getting-started/bot.md"};function n(s,t,l,d,g,h){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="bot-management" tabindex="-1">Bot Management <a class="header-anchor" href="#bot-management" aria-label="Permalink to &quot;Bot Management&quot;">​</a></h1><p>A Bot is an independent AI agent that comes with its own isolated container, persistent memory, and configurable personality. Bots can chat via various messaging platforms (Channels) and perform complex tasks using specialized tools.</p><h2 id="creating-a-bot" tabindex="-1">Creating a Bot <a class="header-anchor" href="#creating-a-bot" aria-label="Permalink to &quot;Creating a Bot&quot;">​</a></h2><ol><li>Navigate to the <strong>Bots</strong> page from the sidebar.</li><li>Click the <strong>Create Bot</strong> button.</li><li>Fill in the basic info: <ul><li><strong>Display Name</strong>: The name users will see in group chats.</li><li><strong>Avatar</strong>: A URL for the bot&#39;s profile picture.</li><li><strong>Type</strong>: Choose <code>personal</code> (private to owner) or <code>public</code> (accessible to guests).</li></ul></li><li>Click <strong>Create</strong>.</li></ol><hr><h2 id="bot-detail-page" tabindex="-1">Bot Detail Page <a class="header-anchor" href="#bot-detail-page" aria-label="Permalink to &quot;Bot Detail Page&quot;">​</a></h2><p>Once created, clicking on a bot card takes you to its <strong>Detail Page</strong>, where you can manage its entire lifecycle through several specialized tabs.</p><h3 id="overview-tab" tabindex="-1">Overview Tab <a class="header-anchor" href="#overview-tab" aria-label="Permalink to &quot;Overview Tab&quot;">​</a></h3><p>The <strong>Overview</strong> tab provides a quick health check of the bot&#39;s services. It monitors:</p><ul><li>Container status (running/stopped)</li><li>Database connectivity</li><li>Channel configurations</li><li>Memory system health</li></ul><p>If any check shows a warning or error, follow the provided details to troubleshoot.</p><h2 id="configuring-the-bot-s-core-settings" tabindex="-1">Configuring the Bot&#39;s Core Settings <a class="header-anchor" href="#configuring-the-bot-s-core-settings" aria-label="Permalink to &quot;Configuring the Bot&#39;s Core Settings&quot;">​</a></h2><p>After creating a bot, the most important step is configuring its runtime settings. These define how the bot talks, remembers, searches, and uses browser automation.</p><ol><li>Navigate to your bot&#39;s <strong>Detail Page</strong>.</li><li>Go to the <strong>Settings</strong> tab.</li><li>Configure the core fields: <ul><li><strong>Chat Model</strong>: Used for standard conversations with users.</li><li><strong>Memory Provider</strong>: Select the memory backend the bot should use.</li><li><strong>Search Provider</strong>: Select the search engine provider for web search.</li><li><strong>Browser Context</strong>: Select the browser profile the bot should use for browser automation.</li></ul></li><li>Click <strong>Save</strong> at the bottom of the form.</li></ol><p>If you have not created these resources yet, set them up first:</p><ul><li><a href="/getting-started/provider-and-model.html">LLM Provider and Model</a></li><li><a href="/memory-providers/builtin.html">Built-in Memory Provider</a></li><li><a href="/getting-started/search-provider.html">Search Providers</a></li><li><a href="/getting-started/browser.html">Browser Contexts</a></li></ul><hr><h2 id="settings-tab-reference" tabindex="-1">Settings Tab Reference <a class="header-anchor" href="#settings-tab-reference" aria-label="Permalink to &quot;Settings Tab Reference&quot;">​</a></h2><p>The <strong>Settings</strong> tab contains all the core parameters that define your bot&#39;s behavior and runtime configuration.</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Chat Model</strong></td><td>The main LLM used for generating chat responses.</td></tr><tr><td><strong>Memory Provider</strong></td><td>The memory backend assigned to the bot. The built-in provider can optionally define its own memory and embedding models.</td></tr><tr><td><strong>Search Provider</strong></td><td>The search engine used for web browsing capabilities.</td></tr><tr><td><strong>Browser Context</strong></td><td>The browser environment used for web automation, such as viewport, locale, and mobile behavior.</td></tr><tr><td><strong>Max Context Load Time</strong></td><td>Time limit (seconds) for loading context before generation.</td></tr><tr><td><strong>Max Context Tokens</strong></td><td>Token limit for the loaded conversation history.</td></tr><tr><td><strong>Language</strong></td><td>The bot&#39;s primary communication language.</td></tr><tr><td><strong>Reasoning Enabled</strong></td><td>If the selected model supports reasoning (like OpenAI o1), enable this to use its deep thinking capabilities.</td></tr><tr><td><strong>Reasoning Effort</strong></td><td>Set the level of reasoning effort (<code>low</code>, <code>medium</code>, <code>high</code>).</td></tr><tr><td><strong>Allow Guest</strong></td><td>(Public bots only) If enabled, non-registered users can interact with the bot.</td></tr></tbody></table><hr><h2 id="deleting-a-bot" tabindex="-1">Deleting a Bot <a class="header-anchor" href="#deleting-a-bot" aria-label="Permalink to &quot;Deleting a Bot&quot;">​</a></h2><p>To permanently remove a bot and all its associated data (including container files and memory):</p><ol><li>Navigate to the <strong>Settings</strong> tab in the Bot Detail page.</li><li>Scroll to the <strong>Danger Zone</strong> at the bottom.</li><li>Click <strong>Delete Bot</strong> and confirm the action.</li></ol><blockquote><p><strong>Warning</strong>: This action is irreversible. All persistent data for this bot will be lost.</p></blockquote>',25)])])}const m=e(i,[["render",n]]);export{b as __pageData,m as default};
